#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    bool dfs(vector<vector<char>>& board, const string& word, int r, int c, int k) {
        if (k == word.length()) return true;
        if (r < 0 || r >= board.size() || c < 0 || c >= board[0].size() || board[r][c] != word[k]) {
            return false;
        }
        char temp = board[r][c];
        board[r][c] = '#';
        bool res = dfs(board, word, r + 1, c, k + 1) ||
                   dfs(board, word, r - 1, c, k + 1) ||
                   dfs(board, word, r, c + 1, k + 1) ||
                   dfs(board, word, r, c - 1, k + 1);
        board[r][c] = temp;
        return res;
    }

public:
    bool exist(vector<vector<char>>& board, string word) {
        for (int i = 0; i < board.size(); i++) {
            for (int j = 0; j < board[0].size(); j++) {
                if (dfs(board, word, i, j, 0)) return true;
            } 
        }
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int m, n;
    if (!(cin >> m >> n)) return 0;
    vector<vector<char>> board(m, vector<char>(n));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            cin >> board[i][j];
        }
    }
    string word;
    if (!(cin >> word)) return 0;
    Solution sol;
    bool ans = sol.exist(board, word);
    cout << (ans ? "true" : "false") << "\n";
    return 0;
}
